+func TestFormatForAgent(t *testing.T) {
+	tests := []struct {
+		agentType string
+		want      InjectionFormat
+	}{
+		{"claude", FormatMarkdown},
+		{"cc", FormatMarkdown},
+		{"Claude", FormatMarkdown},
+		{"codex", FormatMinimal},
+		{"cod", FormatMinimal},
+		{"Codex", FormatMinimal},
+		{"gemini", FormatStructured},
+		{"gmi", FormatStructured},
+		{"Gemini", FormatStructured},
+		{"unknown", FormatMarkdown}, // Default
